import { Slot } from "@radix-ui/react-slot";
import { tv, type VariantProps } from "tailwind-variants";
import { cn } from "@/lib/utils";

const badgeVariants = tv({
  base: [
    "inline-flex items-center justify-center gap-1",
    "px-1 py-0.5",
    "rounded-md border",
    "select-none font-medium text-xs",
    "overflow-hidden",
    "outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
    "[&>svg]:pointer-events-none [&>svg]:size-3",
  ],
  variants: {
    variant: {
      default: [
        "bg-primary text-primary-foreground",
        "[a&]:hover:bg-primary/90",
      ],
      secondary: [
        "bg-secondary text-secondary-foreground",
        "[a&]:hover:bg-secondary/90",
      ],
      destructive: [
        "bg-destructive dark:bg-destructive/60",
        "text-destructive-foreground",
        "focus-visible:ring-destructive/20",
        "dark:focus-visible:ring-destructive/40",
        "[a&]:hover:bg-destructive/90",
      ],
      outline: ["[a&]:hover:bg-accent", "[a&]:hover:text-accent-foreground"],
    },
  },
});

interface BadgeProps
  extends React.ComponentProps<"span">,
    VariantProps<typeof badgeVariants> {
  /**
   * If `true`, the badge will render the child as a slot.
   *
   * @default false
   */
  asChild?: boolean;
}

export const Badge = (props: BadgeProps) => {
  const { asChild, variant = "default", className, ...rest } = props;

  const Comp = asChild ? Slot : "span";

  return (
    <Comp
      className={cn(badgeVariants({ variant }), className)}
      data-part="badge"
      {...rest}
    />
  );
};

import { Slot } from "@radix-ui/react-slot";
import { cn } from "fumadocs-ui/utils/cn";
import type * as React from "react";
import { tv, type VariantProps } from "tailwind-variants";

export const buttonVariants = tv({
  base: [
    "inline-flex shrink-0 items-center justify-center gap-2",
    "whitespace-nowrap font-medium text-sm",
    "rounded-md",
    "transition-all",
    "outline-none focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50",
    "disabled:pointer-events-none disabled:opacity-64",
    "aria-invalid:border-destructive aria-invalid:ring-destructive/20",
    "[&_svg:not([class*='size-'])]:size-4 [&_svg]:pointer-events-none [&_svg]:shrink-0",
  ],
  variants: {
    variant: {
      solid: ["bg-primary", "text-primary-foreground", "hover:bg-primary/90"],
      destructive: [
        "bg-destructive",
        "text-white",
        "hover:bg-destructive/90",
        "focus-visible:ring-destructive/20",
        "dark:bg-destructive/60 dark:focus-visible:ring-destructive/40",
      ],
      outline: [
        "bg-background",
        "border shadow-xs",
        "hover:bg-accent hover:text-accent-foreground",
        "dark:border-input dark:bg-input/30 dark:hover:bg-input/50",
      ],
      secondary: [
        "bg-secondary",
        "text-secondary-foreground",
        "hover:bg-secondary/80",
      ],
      ghost: ["hover:bg-accent hover:text-accent-foreground"],
      link: ["text-primary", "underline-offset-4", "hover:underline"],
    },
    size: {
      sm: ["h-8", "gap-1.5", "rounded-md", "px-3", "has-[>svg]:px-2.5"],
      md: ["h-9", "px-4", "py-2", "has-[>svg]:px-3"],
      lg: ["h-10", "rounded-md", "px-6", "has-[>svg]:px-4"],
      "icon-sm": "size-8",
      "icon-md": "size-9",
      "icon-lg": "size-10",
    },
  },
  defaultVariants: {
    variant: "solid",
    size: "md",
  },
});

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  /**
   * If `true`, the button will render the child as a slot.
   *
   * @default false
   */
  asChild?: boolean;
}

export const Button = (props: ButtonProps) => {
  const { asChild, variant, size, className, ...rest } = props;

  const Comp = asChild ? Slot : "button";

  return (
    <Comp
      className={cn(buttonVariants({ variant, size }), className)}
      {...rest}
    />
  );
};

import { cn } from "@/lib/utils";

interface CardProps extends React.ComponentProps<"div"> {
  /**
   * The spacing variable value
   */
  spacing?: number;
}

export const Card = (props: CardProps) => {
  const { spacing = 6, className, style, ...rest } = props;

  return (
    <div
      className={cn(
        "group/card",
        "py-(--space)",
        "flex flex-col gap-(--space)",
        "bg-background",
        "text-foreground",
        "rounded-lg border shadow-xs",
        "has-[table]:overflow-hidden **:[table]:overflow-hidden",
        "has-[table]:not-has-data-[slot=card-footer]:pb-0 has-[table]:**:data-[slot=card-footer]:border-t",
        "**:data-[slot=table-header]:bg-muted/50",
        className
      )}
      data-part="root"
      data-scope="card"
      data-spacing={spacing}
      style={
        {
          "--space": `calc(${spacing} * var(--spacing))`,
          ...style,
        } as React.CSSProperties
      }
      {...rest}
    />
  );
};

interface HeaderProps extends React.ComponentProps<"div"> {
  /**
   * The title of the card
   */
  title?: string;
  /**
   * The description of the card
   */
  description?: string;
}

export const CardHeader = (props: HeaderProps) => {
  const { className, title, description, children, ...rest } = props;

  return (
    <div
      className={cn(
        "grid auto-rows-min grid-rows-[auto_auto] gap-1",
        "px-(--space)",
        "items-start",
        "has-data-[slot=card-action]:grid-cols-[1fr_auto]",
        className
      )}
      data-part="header"
      data-scope="card"
      {...rest}
    >
      {title && <CardTitle>{title}</CardTitle>}
      {description && <CardDescription>{description}</CardDescription>}
      {!title && typeof children === "string" ? (
        <CardTitle>{children}</CardTitle>
      ) : (
        children
      )}
    </div>
  );
};

export const CardTitle = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn(
        " font-semibold text-foreground text-lg/6 sm:text-base/6",
        className
      )}
      data-part="title"
      data-scope="card"
      {...rest}
    />
  );
};

export const CardDescription = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn(
        "row-start-2",
        " text-muted-foreground text-sm",
        className
      )}
      data-part="description"
      data-scope="card"
      {...rest}
    />
  );
};

export const CardAction = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn(
        "col-start-2 row-span-2 row-start-1 self-start justify-self-end",
        className
      )}
      data-part="action"
      data-scope="card"
      {...rest}
    />
  );
};

export const CardContent = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn("px-(--space) has-[table]:border-t", className)}
      data-part="content"
      data-scope="card"
      {...rest}
    />
  );
};

export const CardFooter = (props: React.ComponentProps<"div">) => {
  const { className, ...rest } = props;

  return (
    <div
      className={cn(
        "flex items-center",
        "px-(--space)",
        "group-has-[table]/card:pt-(--space)",
        "[.border-t]:pt-(--space)",
        className
      )}
      data-part="footer"
      data-scope="card"
      {...rest}
    />
  );
};

import { Checkbox as ArkCheckbox } from "@ark-ui/react/checkbox";
import { Check } from "lucide-react";
import type React from "react";
import { cn } from "@/lib/utils";

export const CheckboxGroup = (
  props: React.ComponentProps<typeof ArkCheckbox.Group>
) => {
